        .query<[Array<{ count: number }>]>(
          [
            "SELECT count() AS count",
            "FROM task",
            "WHERE status != 'done'",
            "AND (",
            "  id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
